import React, { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import Sidebar from "../components/CampaignTable";

export default function CampaignHistory() {
  const [campaigns, setCampaigns] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState("all");
  const [activeSection, setActiveSection] = useState("recent");
  const navigate = useNavigate();

  useEffect(() => {
    const fetchCampaigns = async () => {
      try {
        const token = localStorage.getItem("token");
        if (!token) {
          navigate("/login");
          return;
        }

        const res = await axios.get("http://localhost:5000/api/campaigns", {
          headers: { Authorization: `Bearer ${token}` }
        });
        setCampaigns(res.data);
      } catch (error) {
        console.error("Error fetching campaigns:", error);
        if (error.response?.status === 401) {
          localStorage.removeItem("token");
          navigate("/login");
        }
      } finally {
        setLoading(false);
      }
    };

    fetchCampaigns();
  }, [navigate]);

  const recentCampaigns = campaigns.slice(0, 5);
  const olderCampaigns = campaigns.slice(5);

  const filteredRecentCampaigns = recentCampaigns.filter(campaign => {
    if (filter === "all") return true;
    return campaign.type === filter;
  });

  const filteredOlderCampaigns = olderCampaigns.filter(campaign => {
    if (filter === "all") return true;
    return campaign.type === filter;
  });

  if (loading) {
    return (
      <div className="flex items-center justify-center h-screen">
        <div className="text-xl">Loading campaign history...</div>
      </div>
    );
  }

  return (
    <div className="flex">
      <Sidebar />
      <div className="p-6 w-full bg-gray-100">
        <div className="flex justify-between items-center mb-6">
          <h1 className="text-2xl font-bold">Campaign Management</h1>
          <div className="flex items-center gap-4">
            <label className="text-sm font-medium">Filter:</label>
            <select
              value={filter}
              onChange={(e) => setFilter(e.target.value)}
              className="border p-2 rounded"
            >
              <option value="all">All Campaigns</option>
              <option value="whatsapp">WhatsApp</option>
              <option value="sms">SMS</option>
            </select>
          </div>
        </div>

        {/* Section Tabs */}
        <div className="flex gap-4 mb-6 border-b">
          <button
            onClick={() => setActiveSection("recent")}
            className={`pb-3 px-4 font-medium transition-colors ${
              activeSection === "recent"
                ? "border-b-2 border-blue-500 text-blue-600"
                : "text-gray-600 hover:text-gray-800"
            }`}
          >
            📊 Recent Campaigns ({filteredRecentCampaigns.length})
          </button>
          <button
            onClick={() => setActiveSection("history")}
            className={`pb-3 px-4 font-medium transition-colors ${
              activeSection === "history"
                ? "border-b-2 border-blue-500 text-blue-600"
                : "text-gray-600 hover:text-gray-800"
            }`}
          >
            📋 Campaign History ({filteredOlderCampaigns.length})
          </button>
        </div>

        {/* Recent Campaigns Section */}
        {activeSection === "recent" && (
          <div className="space-y-4">
            {filteredRecentCampaigns.length === 0 ? (
              <div className="bg-white rounded-lg shadow p-8 text-center">
                <p className="text-gray-500 text-lg mb-4">
                  {filter === "all" 
                    ? "No recent campaigns found" 
                    : `No recent ${filter} campaigns found`
                  }
                </p>
                <button
                  onClick={() => navigate("/dashboard")}
                  className="bg-blue-500 text-white px-6 py-3 rounded-lg hover:bg-blue-600 transition-colors"
                >
                  Create First Campaign
                </button>
              </div>
            ) : (
              <div className="grid gap-4">
                {filteredRecentCampaigns.map((campaign) => (
                  <div key={campaign.id} className="bg-white rounded-lg shadow p-6 hover:shadow-lg transition-shadow">
                    <div className="flex justify-between items-start mb-4">
                      <div className="flex-1">
                        <h3 className="text-lg font-semibold text-gray-900 mb-2">{campaign.name}</h3>
                        <p className="text-gray-600 text-sm mb-3 line-clamp-2">
                          {campaign.message}
                        </p>
                      </div>
                      <div className="flex gap-2 ml-4">
                        <span className={`px-3 py-1 rounded-full text-xs font-medium ${
                          campaign.type === 'whatsapp' 
                            ? 'bg-green-100 text-green-800' 
                            : 'bg-blue-100 text-blue-800'
                        }`}>
                          {campaign.type.toUpperCase()}
                        </span>
                        <span className={`px-3 py-1 rounded-full text-xs font-medium ${
                          campaign.status === 'completed' 
                            ? 'bg-green-100 text-green-800' 
                            : 'bg-yellow-100 text-yellow-800'
                        }`}>
                          {campaign.status || 'pending'}
                        </span>
                      </div>
                    </div>

                    <div className="flex justify-between items-center text-sm text-gray-600">
                      <div className="flex gap-6">
                        <span>👥 {campaign.recipients} recipients</span>
                        <span>📁 {campaign.recipients_file ? 'File uploaded' : 'No file'}</span>
                        <span>🕒 {new Date(campaign.created_at).toLocaleDateString()}</span>
                      </div>
                      <div className="flex gap-3">
                        <button
                          onClick={() => alert(`View details for: ${campaign.name}`)}
                          className="text-blue-500 hover:text-blue-700 font-medium"
                        >
                          View Details
                        </button>
                        <button
                          onClick={() => alert(`Duplicate campaign: ${campaign.name}`)}
                          className="text-green-500 hover:text-green-700 font-medium"
                        >
                          Duplicate
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* Campaign History Section */}
        {activeSection === "history" && (
          <div className="bg-white rounded-lg shadow">
            {filteredOlderCampaigns.length === 0 ? (
              <div className="p-8 text-center">
                <p className="text-gray-500 text-lg">
                  {filter === "all" 
                    ? "No older campaigns found" 
                    : `No older ${filter} campaigns found`
                  }
                </p>
              </div>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead>
                    <tr className="border-b bg-gray-50">
                      <th className="text-left p-3 font-medium">Campaign Name</th>
                      <th className="text-left p-3 font-medium">Type</th>
                      <th className="text-left p-3 font-medium">Recipients</th>
                      <th className="text-left p-3 font-medium">Status</th>
                      <th className="text-left p-3 font-medium">File</th>
                      <th className="text-left p-3 font-medium">Created</th>
                      <th className="text-left p-3 font-medium">Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredOlderCampaigns.map((campaign) => (
                      <tr key={campaign.id} className="border-b hover:bg-gray-50">
                        <td className="p-3">
                          <div>
                            <div className="font-medium">{campaign.name}</div>
                            <div className="text-sm text-gray-600 truncate max-w-xs">
                              {campaign.message.substring(0, 50)}...
                            </div>
                          </div>
                        </td>
                        <td className="p-3">
                          <span className={`px-2 py-1 rounded text-xs font-medium ${
                            campaign.type === 'whatsapp' 
                              ? 'bg-green-100 text-green-800' 
                              : 'bg-blue-100 text-blue-800'
                          }`}>
                            {campaign.type.toUpperCase()}
                          </span>
                        </td>
                        <td className="p-3">
                          <span className="font-medium">{campaign.recipients}</span>
                        </td>
                        <td className="p-3">
                          <span className={`px-2 py-1 rounded text-xs font-medium ${
                            campaign.status === 'completed' 
                              ? 'bg-green-100 text-green-800' 
                              : 'bg-yellow-100 text-yellow-800'
                          }`}>
                            {campaign.status || 'pending'}
                          </span>
                        </td>
                        <td className="p-3">
                          {campaign.recipients_file ? (
                            <span className="text-xs text-gray-600">
                              {campaign.recipients_file.substring(0, 20)}...
                            </span>
                          ) : (
                            <span className="text-xs text-gray-400">No file</span>
                          )}
                        </td>
                        <td className="p-3">
                          <div className="text-sm text-gray-600">
                            {new Date(campaign.created_at).toLocaleDateString()}
                            <br />
                            {new Date(campaign.created_at).toLocaleTimeString()}
                          </div>
                        </td>
                        <td className="p-3">
                          <div className="flex gap-2">
                            <button
                              className="text-blue-500 hover:text-blue-700 text-sm font-medium"
                              onClick={() => alert(`View details for: ${campaign.name}`)}
                            >
                              View
                            </button>
                            <button
                              className="text-green-500 hover:text-green-700 text-sm font-medium"
                              onClick={() => alert(`Duplicate campaign: ${campaign.name}`)}
                            >
                              Duplicate
                            </button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        )}

        {/* Quick Actions Bar */}
        <div className="mt-6 bg-white rounded-lg shadow p-4">
          <div className="flex justify-between items-center">
            <div className="text-sm text-gray-600">
              {activeSection === "recent" 
                ? `Showing ${filteredRecentCampaigns.length} recent campaigns`
                : `Showing ${filteredOlderCampaigns.length} older campaigns`
              }
              {filter !== "all" && ` (${filter})`}
            </div>
            <div className="flex gap-3">
              {activeSection === "history" && (
                <button
                  onClick={() => setActiveSection("recent")}
                  className="bg-gray-500 text-white px-4 py-2 rounded hover:bg-gray-600 transition-colors"
                >
                  ← Back to Recent
                </button>
              )}
              <button
                onClick={() => navigate("/dashboard")}
                className="bg-blue-500 text-white px-4 py-2 rounded hover:bg-blue-600 transition-colors"
              >
                ➕ Create New Campaign
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
